<?php
namespace Tests\Feature\Hr;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Recruitment\Actions\AdvanceApplicationAction;use App\Modules\Hr\Recruitment\Actions\CreateApplicationAction;use App\Modules\Hr\Recruitment\Actions\CreateJobPostingAction;use App\Modules\Hr\Recruitment\Actions\ManageJobOfferAction;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class RecruitmentWorkflowTest extends TestCase{use RefreshHrDatabase;private User $user;private LegalEntity $tenant;protected function setUp():void{parent::setUp();(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$this->user=User::factory()->create(['role_id'=>$role]);$this->actingAs($this->user);$this->tenant=LegalEntity::create(['user_id'=>$this->user->id,'name'=>'Aday','tax_number'=>'7171717171','is_active'=>true]);app(TenantContext::class)->set($this->tenant);}public function test_human_stages_and_offer_require_separate_approval():void{$posting=app(CreateJobPostingAction::class)->execute(['code'=>'DEV','title'=>'Geliştirici','headcount'=>1]);$application=app(CreateApplicationAction::class)->execute($posting,['first_name'=>'Ada','last_name'=>'Aday','email'=>'ada@example.com','consent_note'=>'KVKK açık rıza formu']);$advance=app(AdvanceApplicationAction::class);foreach(['screening','interview','reference','offer'] as $stage)$application=$advance->execute($application,$stage,85,'İnsan değerlendirmesi');$offer=app(ManageJobOfferAction::class)->create($application,['gross_salary'=>50000,'proposed_start_date'=>today()->addMonth(),'expires_on'=>today()->addWeek()]);$this->assertSame('pending_approval',$offer->status);$approved=app(ManageJobOfferAction::class)->approve($offer,'Bütçe ve kadro onaylandı');$this->assertSame('approved',$approved->status);$this->assertNotNull($approved->approved_at);}public function test_rejection_requires_human_reason():void{$posting=app(CreateJobPostingAction::class)->execute(['code'=>'OPS','title'=>'Operasyon','headcount'=>1]);$application=app(CreateApplicationAction::class)->execute($posting,['first_name'=>'Ali','last_name'=>'Aday','email'=>'ali@example.com','consent_note'=>'Açık rıza']);$this->expectException(\Symfony\Component\HttpKernel\Exception\HttpException::class);app(AdvanceApplicationAction::class)->reject($application,'');}}
